mapper.select:
SELECT

FROM sys_menu a

WHERE a.id = #{id}

        SELECT

        FROM sys_menu a
        LEFT JOIN sys_menu p ON p.id = a.parent_id
        JOIN sys_role_menu rm ON rm.menu_id = a.id
        JOIN sys_role r ON r.id = rm.role_id AND r.useable='1'
        JOIN sys_user_role ur ON ur.role_id = r.id
        JOIN sys_user u ON u.id = ur.user_id AND u.id = #{menu.userId}
        WHERE a.del_flag = #{menu.DEL_FLAG_NORMAL}
        AND r.del_flag = #{menu.DEL_FLAG_NORMAL}
        AND u.del_flag = #{menu.DEL_FLAG_NORMAL}
        AND a.id != '1' /*AND a.is_show = '1'*/

			AND a.id in (
			    select menu_id from sys_subsystem_menu  a
			     inner join sys_subsystem b on a.subsystem_id = b.id
			     where b.code = #{subSystemCode}
			)

        ORDER BY a.sort

SELECT

FROM sys_menu a
LEFT JOIN sys_menu p ON p.id = a.parent_id
JOIN sys_user u ON u.id =  #{menu.userId}
JOIN sys_office so ON so.id = u.office_id
JOIN sys_office_menu om ON om.menu_id = a.id and om.office_id = so.id

WHERE a.del_flag = #{menu.DEL_FLAG_NORMAL}
AND so.del_flag = #{menu.DEL_FLAG_NORMAL}
AND u.del_flag = #{menu.DEL_FLAG_NORMAL}
AND a.id != '1' /*AND a.is_show = '1'*/

	AND a.id in (
	select menu_id from sys_subsystem_menu  a
	inner join sys_subsystem b on a.subsystem_id = b.id
	where b.code = #{subSystemCode}
	)

ORDER BY a.sort

SELECT DISTINCT a.permission
FROM sys_menu a
LEFT JOIN sys_menu p ON p.id = a.parent_id
JOIN sys_role_menu rm ON rm.menu_id = a.id
JOIN sys_role r ON r.id = rm.role_id AND r.useable='1'
JOIN sys_user_role ur ON ur.role_id = r.id
JOIN sys_user u ON u.id = ur.user_id AND u.id = #{userId}
WHERE a.del_flag = #{DEL_FLAG_NORMAL}
AND r.del_flag = #{DEL_FLAG_NORMAL}
AND u.del_flag = #{DEL_FLAG_NORMAL}
AND a.permission IS NOT NULL

SELECT a.* ,(select case when exists(select 1 from sys_menu where parent_id = a.id) then 1 else 0 end from sys_dual) AS "hasChildren" FROM sys_menu a WHERE a.del_flag = #{DEL_FLAG_NORMAL}
AND a.parent_id = #{id}
AND a.parent_id = '0'
ORDER BY sort

mapper.update:
UPDATE sys_menu SET
	sort = #{sort}
WHERE id = #{id}

